import torch
import os


def resume_training_from_checkpoint(checkpoint_path: str) -> dict:
    """
    Load a training checkpoint from the specified path and return its contents.

    Args:
        checkpoint_path: Path to the checkpoint file (.ckpt or .pth)

    Returns:
        Dictionary containing model state, optimizer state, and training metadata

    Raises:
        FileNotFoundError: If checkpoint file doesn't exist
        ValueError: If checkpoint file has unsafe extension or content
        RuntimeError: If torch.load fails or returns unexpected data
    """
    # Validate file exists
    if not os.path.exists(checkpoint_path):
        raise FileNotFoundError(f"Checkpoint file not found: {checkpoint_path}")

    # Validate file extension
    safe_extensions = {'.ckpt', '.pth', '.pt'}
    file_ext = os.path.splitext(checkpoint_path)[1].lower()
    if file_ext not in safe_extensions:
        raise ValueError(
            f"Unsafe file extension: {file_ext}. "
            f"Allowed extensions: {', '.join(safe_extensions)}"
        )

    try:
        # Use weights_only=True to prevent arbitrary code execution
        checkpoint_data = torch.load(checkpoint_path, weights_only=True)
    except Exception as e:
        raise RuntimeError(f"Failed to load checkpoint: {str(e)}")

    # Validate loaded data structure
    if not isinstance(checkpoint_data, dict):
        raise ValueError(
            f"Checkpoint must contain a dictionary, got {type(checkpoint_data)}"
        )

    # Handle different checkpoint formats
    if 'model_state_dict' in checkpoint_data:
        # It's a full checkpoint, ensure all expected keys are present with defaults if missing
        expected_keys = {'model_state_dict', 'optimizer_state_dict', 'epoch', 'loss'}
        for key in expected_keys:
            if key not in checkpoint_data:
                checkpoint_data[key] = None
        # Set default for epoch if None to 0 for resuming training
        if checkpoint_data['epoch'] is None:
            checkpoint_data['epoch'] = 0
        return checkpoint_data
    else:
        # Assume checkpoint_data is the model state_dict, return it directly
        return checkpoint_data
